  6→export interface ClickHouseExecutor {
  7→	execute(sql: string): Promise<void>;
  8→	query<T>(sql: string): Promise<T[]>;
  9→	insert(params: { table: string; values: object[] }): Promise<void>;
 10→}
 11→
 12→export function createClickHouseExecutor(config: {
 13→	url: string;
 14→	username?: string;
 15→	password?: string;
 16→	database?: string;
 17→}): ClickHouseExecutor {
 18→	const client = createClient({
 19→		url: config.url,
 20→		username: config.username,
 21→		password: config.password,
 22→		database: config.database,
 23→		request_timeout: 120_000,
 24→		clickhouse_settings: {
 25→			wait_end_of_query: 1,
 26→			output_format_json_quote_64bit_integers: 0,
 27→		},
 28→	});
 29→	return {
 30→		async execute(sql) {
 31→			await client.command({ query: sql });
 32→		},
 33→		async query<T>(sql: string): Promise<T[]> {
 34→			const result = await client.query({
 35→				query: sql,
 36→				format: "JSONEachRow",
 37→			});
 38→			return result.json();
 39→		},
 40→		async insert(params) {
 41→			// Use command() with FORMAT JSONEachRow instead of client.insert()
 42→			// because ClickHouse Cloud's @clickhouse/client insert() silently drops data.
 43→			const rows = params.values.map((r) => JSON.stringify(r)).join("\n");
 44→			await client.command({
 45→				query: `INSERT INTO ${params.table} SETTINGS async_insert=0 FORMAT JSONEachRow ${rows}`,
 46→			});
 47→		},
 48→	};
 49→}
 50→
 51→let _clickhouse: ClickHouseExecutor | null = null;
 52→
 53→export function getClickhouse(): ClickHouseExecutor {
 54→	if (!_clickhouse) {
 55→		const executor = createClickHouseExecutor({
 56→			url: process.env.CLICKHOUSE_URL || "http://localhost:8123",
 57→			username:
 58→				process.env.CLICKHOUSE_USERNAME ||
 59→				process.env.CLICKHOUSE_USER ||
 60→				"default",
 61→			password: process.env.CLICKHOUSE_PASSWORD || "",
 62→			database: "default",
 63→		});
 64→		const maxRetries = 3;
 65→		_clickhouse = {
 66→			...executor,
 67→			async insert(params) {
 68→				for (let attempt = 0; attempt < maxRetries; attempt++) {
 69→					try {
 70→						return await executor.insert(params);
 71→					} catch (error) {
 72→						if (attempt === maxRetries - 1) {
 73→							logger.error(
 74→								"Insert into {table} failed after {maxRetries} attempts: {error}",
 75→								{ table: params.table, maxRetries, error },
 76→							);
 77→							throw error;
 78→						}
 79→						logger.warn(
 80→							"Insert into {table} failed (attempt {attempt}/{maxRetries}), retrying: {error}",
 81→							{
 82→								table: params.table,
 83→								attempt: attempt + 1,
 84→								maxRetries,
 85→								error,
 86→							},
 87→						);
 88→						await new Promise((r) => setTimeout(r, 100 * (attempt + 1)));
 89→					}
 90→				}
 91→			},
 92→		};
 93→	}
 94→	return _clickhouse;
 95→}
