 28→		activeOrganizationId:
 29→			((context.session as Record<string, unknown>).activeOrganizationId as
 30→				| string
 31→				| null) ?? null,
 32→	};
 33→});
 34→
 35→const listMyOrganizations = os.listMyOrganizations
 36→	.use(authMiddleware)
 37→	.handler(async ({ context }) => {
 38→		const memberships = await db
 39→			.select({
 40→				id: organization.id,
 41→				name: organization.name,
 42→				slug: organization.slug,
 43→				logo: organization.logo,
 44→			})
 45→			.from(member)
 46→			.innerJoin(organization, eq(member.organizationId, organization.id))
 47→			.where(eq(member.userId, context.user.id));
 48→
 49→		return memberships.map((m) => ({
 50→			id: m.id,
 51→			name: m.name,
 52→			slug: m.slug,
 53→			logo: m.logo ?? null,
 54→		}));
 55→	});
 56→
 57→const ingestSessionHandler = os.ingestSession
 58→	.use(authMiddleware)
 59→	.handler(async ({ input, context }) => {
 60→		await checkIngestRateLimit(context.user.id);
 61→
 62→		const orgId =
 63→			input.organizationId ??
 64→			((context.session as Record<string, unknown>).activeOrganizationId as
 65→				| string
 66→				| null) ??
 67→			context.user.id;
 68→
 69→		// Verify membership for any org that isn't the user's personal workspace
 70→		if (orgId !== context.user.id) {
 71→			const membership = await db
 72→				.select({ id: member.id })
 73→				.from(member)
 74→				.where(
 75→					and(
 76→						eq(member.organizationId, orgId),
 77→						eq(member.userId, context.user.id),
 78→					),
 79→				)
 80→				.limit(1);
 81→
 82→			if (membership.length === 0) {
 83→				throw new ORPCError("FORBIDDEN", {
 84→					message: "Not a member of the specified organization",
 85→				});
 86→			}
 87→		}
 88→
 89→		const adapter = getAdapter(input.source);
 90→		await adapter.ingest(getClickhouse(), input, {
 91→			userId: context.user.id,
 92→			organizationId: orgId,
 93→		});
 94→
 95→		return {
 96→			success: true as const,
 97→			sessionId: input.sessionId,
 98→		};
 99→	});
100→
101→const getOrganizationSessionCount = os.getOrganizationSessionCount
102→	.use(authMiddleware)
103→	.handler(async ({ input, context }) => {
104→		const membership = await db
105→			.select({ id: member.id })
106→			.from(member)
107→			.where(
108→				and(
109→					eq(member.organizationId, input.organizationId),
110→					eq(member.userId, context.user.id),
111→				),
112→			)
113→			.limit(1);
114→
115→		if (membership.length === 0) {
116→			throw new ORPCError("FORBIDDEN", {
117→				message: "Not a member of this organization",
118→			});
119→		}
120→
121→		const count = await getOrgSessionCount(input.organizationId);
122→		return { count };
123→	});
124→
125→const deleteOrganization = os.deleteOrganization
126→	.use(authMiddleware)
127→	.handler(async ({ input, context }) => {
128→		const orgId = input.organizationId;
129→		const userId = context.user.id;
130→		console.log(`[deleteOrganization] user=${userId} org=${orgId}`);
131→
132→		// Check user has more than one org
133→		const memberships = await db
134→			.select({ organizationId: member.organizationId })
135→			.from(member)
136→			.where(eq(member.userId, userId));
137→
138→		if (memberships.length <= 1) {
139→			console.log(
140→				`[deleteOrganization] rejected: user=${userId} has only ${memberships.length} org(s)`,
141→			);
142→			throw new ORPCError("BAD_REQUEST", {
143→				message: "Cannot delete your only organization",
144→			});
145→		}
146→
147→		// Verify user is owner of the target org
148→		const ownership = await db
149→			.select({ id: member.id })
150→			.from(member)
151→			.where(
152→				and(
153→					eq(member.organizationId, orgId),
154→					eq(member.userId, userId),
155→					eq(member.role, "owner"),
156→				),
157→			)
158→			.limit(1);
159→
160→		if (ownership.length === 0) {
161→			console.log(
162→				`[deleteOrganization] rejected: user=${userId} is not owner of org=${orgId}`,
163→			);
164→			throw new ORPCError("FORBIDDEN", {
165→				message: "Only the organization owner can delete it",
166→			});
167→		}
168→
169→		try {
170→			// Fire-and-forget: ClickHouse mutations are slow, don't block on them
171→			deleteOrgSessions(orgId);
172→
173→			// Delete the organization from Postgres (cascade handles member + invitation)
174→			console.log(`[deleteOrganization] deleting org=${orgId} from Postgres`);
175→			await db.delete(organization).where(eq(organization.id, orgId));
176→
177→			// Clear activeOrganizationId on user sessions that reference the deleted org
178→			console.log(
179→				`[deleteOrganization] clearing activeOrganizationId references for org=${orgId}`,
180→			);
181→			await db
182→				.update(session)
183→				.set({ activeOrganizationId: null })
184→				.where(eq(session.activeOrganizationId, orgId));
185→
186→			console.log(`[deleteOrganization] success for org=${orgId}`);
187→			return { success: true as const };
188→		} catch (error) {
189→			if (error instanceof ORPCError) throw error;
190→			console.error(`[deleteOrganization] failed for org=${orgId}:`, error);
191→			throw error;
192→		}
193→	});
194→
195→export const router = os.router({
196→	health,
197→	me,
198→	listMyOrganizations,
199→	ingestSession: ingestSessionHandler,
200→	getOrganizationSessionCount,
201→	deleteOrganization,
202→	analytics: analyticsRouter,
203→});
204→

